749→fn frontend_config(
750→    language: Language,
751→    timeout: Duration,
752→    log_level: LogLevel,
753→    exec_timeout: u64,
754→    build_timeout: u64,
755→    memory_limit: Option<u64>,
756→    shatter_dir: Option<&Path>,
757→) -> Result<FrontendConfig, String> {
758→    let (command, mut args) = match language {
759→        Language::TypeScript => {
760→            let bundle_path = embedded_frontend::ensure_extracted()?;
761→            (
762→                PathBuf::from("node"),
763→                vec!["--no-warnings".to_string(), bundle_path.to_string_lossy().into_owned()],
764→            )
765→        }
766→        Language::Go => {
767→            if let Some(custom) = find_custom_binary(shatter_dir, "go") {
768→                (custom, vec![])
769→            } else {
770→                let binary_path = embedded_go_frontend::ensure_extracted()?;
771→                (binary_path, vec![])
772→            }
773→        }
774→        Language::Rust => {
775→            if let Some(custom) = find_custom_binary(shatter_dir, "rust") {
776→                (custom, vec![])
777→            } else if let Some(path) = find_on_path("shatter-rust") {
778→                (path, vec![])
779→            } else {
780→                // shatter-rust is outside the workspace, so check both locations
781→                let candidates = [
782→                    PathBuf::from("./shatter-rust/target/debug/shatter-rust"),
783→                    PathBuf::from("./target/debug/shatter-rust"),
784→                ];
785→                if let Some(path) = candidates.iter().find(|p| p.is_file()) {
786→                    (path.clone(), vec![])
787→                } else {
788→                    return Err("shatter-rust frontend not found: install it on PATH or build with `cargo build --manifest-path shatter-rust/Cargo.toml`".to_string());
789→                }
790→            }
791→        }
792→    };
793→
794→    // Apply memory limit: for TS, --max-old-space-size must come before the script
795→    if let Some(mb) = memory_limit {
796→        match language {
797→            Language::TypeScript => {
798→                args.insert(0, format!("--max-old-space-size={mb}"));
799→            }
800→            Language::Go | Language::Rust => {
801→                // Go: GOMEMLIMIT is set via env_vars below
802→                // Rust: no memory limit mechanism yet
803→            }
804→        }
805→    }
806→
807→    let mut config = FrontendConfig::new(command);
808→    config.args = args;
809→    config.request_timeout = timeout;
810→    apply_frontend_env(&mut config, log_level, exec_timeout, build_timeout);
811→
812→    if let Some(mb) = memory_limit
813→        && language == Language::Go
814→    {
815→        let bytes = mb * 1024 * 1024;
816→        config.env_vars.push(("GOMEMLIMIT".to_string(), format!("{bytes}B")));
817→    }
818→
819→    Ok(config)
820→}
