239→/// Why a branch was selected as a GA target.
240→#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
241→#[serde(rename_all = "snake_case")]
242→pub enum TargetReason {
243→    /// Branch was never discovered by any method.
244→    Uncovered,
245→    /// Branch was observed but its constraint is Unknown (opaque to solver).
246→    OpaqueConstraint,
247→}
248→
249→/// A branch that the Genetic Algorithm should target for coverage.
250→#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
251→pub struct TargetBranch {
252→    /// Unique branch identifier within the function.
253→    pub branch_id: u32,
254→    /// Source line number of the branch.
255→    pub line: u32,
256→    /// Why this branch is targeted.
257→    pub reason: TargetReason,
258→    /// Hint about the constraint to guide mutation strategy.
259→    pub constraint_hint: Option<String>,
260→}
261→
262→/// Extract unsolved branch targets from a random exploration result.
263→///
264→/// Compares the static branch list from `analysis` against branches discovered
265→/// during exploration to identify targets the GA should focus on.
266→pub fn extract_targets(
267→    analysis: &FunctionAnalysis,
268→    result: &ObservationOutput,
269→) -> Vec<TargetBranch> {
270→    extract_targets_inner(&analysis.branches, &result.discoveries, &result.raw_results)
271→}
272→
273→/// Extract unsolved branch targets from a concolic exploration result.
274→///
275→/// Same logic as [`extract_targets`] but accepts the orchestrator's result type.
276→pub fn extract_targets_concolic(
277→    analysis: &FunctionAnalysis,
278→    result: &ExploreResult,
279→) -> Vec<TargetBranch> {
280→    extract_targets_inner(&analysis.branches, &result.discoveries, &result.raw_results)
281→}
282→
283→/// Core target extraction logic operating on slices.
284→///
285→/// A branch is targeted if:
286→/// - It was never discovered (not in `discoveries`) → `TargetReason::Uncovered`
287→/// - It was discovered but its runtime constraint is `Unknown` → `TargetReason::OpaqueConstraint`
288→fn extract_targets_inner(
289→    branches: &[BranchInfo],
290→    discoveries: &[(u32, DiscoveryMethod)],
291→    raw_results: &[(Vec<serde_json::Value>, ExecuteResult)],
292→) -> Vec<TargetBranch> {
293→    let discovered: HashSet<u32> = discoveries.iter().map(|(id, _)| *id).collect();
294→
295→    // Collect opaque constraint hints from runtime branch decisions.
296→    let mut opaque_hints: HashMap<u32, String> = HashMap::new();
297→    for (_, exec) in raw_results {
298→        for decision in &exec.branch_path {
299→            if let SymConstraint::Unknown { hint } = &decision.constraint {
300→                opaque_hints
301→                    .entry(decision.branch_id)
302→                    .or_insert_with(|| hint.clone());
303→            }
304→        }
305→    }
306→
307→    let mut targets: Vec<TargetBranch> = Vec::new();
308→    for branch in branches {
309→        if !discovered.contains(&branch.id) {
310→            targets.push(TargetBranch {
311→                branch_id: branch.id,
312→                line: branch.line,
313→                reason: TargetReason::Uncovered,
314→                constraint_hint: if branch.condition_text.is_empty() {
315→                    None
316→                } else {
317→                    Some(branch.condition_text.clone())
318→                },
319→            });
320→        } else if let Some(hint) = opaque_hints.get(&branch.id) {
321→            targets.push(TargetBranch {
322→                branch_id: branch.id,
323→                line: branch.line,
324→                reason: TargetReason::OpaqueConstraint,
325→                constraint_hint: if hint.is_empty() { None } else { Some(hint.clone()) },
326→            });
327→        }
328→    }
329→
330→    targets.sort_by_key(|t| t.branch_id);
331→    targets
332→}
