3301→/// Build a custom frontend binary with user-provided native generators.
3302→fn run_build_frontend(
3303→    language: &str,
3304→    config_dir: Option<&Path>,
3305→    output_dir: Option<&Path>,
3306→) -> Result<(), String> {
3307→    let shatter_dir = config_dir
3308→        .map(PathBuf::from)
3309→        .or_else(|| {
3310→            let candidate = PathBuf::from(".shatter");
3311→            candidate.is_dir().then_some(candidate)
3312→        })
3313→        .ok_or_else(|| "no .shatter/ directory found; pass --config or run from project root".to_string())?;
3314→
3315→    let config_path = shatter_dir.join("config.yaml");
3316→    if !config_path.exists() {
3317→        return Err(format!(
3318→            "config not found: {}",
3319→            config_path.display()
3320→        ));
3321→    }
3322→
3323→    let config = shatter_config::parse_config(&config_path)
3324→        .map_err(|e| format!("failed to load config: {e}"))?;
3325→
3326→    let out_dir = output_dir
3327→        .map(PathBuf::from)
3328→        .unwrap_or_else(|| shatter_dir.join("bin"));
3329→
3330→    std::fs::create_dir_all(&out_dir)
3331→        .map_err(|e| format!("failed to create output dir: {e}"))?;
3332→
3333→    match language {
3334→        "go" => build_go_frontend(&shatter_dir, &config, &out_dir),
3335→        "rust" => build_rust_frontend(&shatter_dir, &config, &out_dir),
3336→        other => Err(format!(
3337→            "unsupported language '{other}'; supported: go, rust"
3338→        )),
3339→    }
3340→}
