3342→/// Collect native generator file paths from config for a given language extension.
3343→fn collect_native_generators(
3344→    config: &ShatterConfig,
3345→    extension: &str,
3346→) -> Vec<(String, PathBuf)> {
3347→    let mut generators = Vec::new();
3348→    let check = |name: &str, path_str: &str| {
3349→        let path = Path::new(path_str);
3350→        if path.extension().and_then(|e| e.to_str()) == Some(extension) {
3351→            Some((name.to_string(), path.to_path_buf()))
3352→        } else {
3353→            None
3354→        }
3355→    };
3356→
3357→    if let Some(ref type_gens) = config.defaults.generators {
3358→        for (name, path_str) in type_gens {
3359→            if let Some(entry) = check(name, path_str) {
3360→                generators.push(entry);
3361→            }
3362→        }
3363→    }
3364→    if let Some(ref param_gens) = config.defaults.param_generators {
3365→        for (name, path_str) in param_gens {
3366→            if let Some(entry) = check(name, path_str) {
3367→                generators.push(entry);
3368→            }
3369→        }
3370→    }
3371→    generators
3372→}
