3374→/// Build a custom Go frontend binary with native generators compiled in.
3375→///
3376→/// Creates a temporary Go module that imports shatter-go's protocol handler and
3377→/// the user's generator files, wires them into the registry, then builds a single
3378→/// binary. Inspired by the xcaddy pattern: replace directives point to local source.
3379→fn build_go_frontend(
3380→    shatter_dir: &Path,
3381→    config: &ShatterConfig,
3382→    out_dir: &Path,
3383→) -> Result<(), String> {
3384→    let native_gens = collect_native_generators(config, "go");
3385→    if native_gens.is_empty() {
3386→        return Err(
3387→            "no .go generators found in config.yaml; nothing to build".to_string(),
3388→        );
3389→    }
3390→
3391→    let output_binary = out_dir.join("shatter-go-custom");
3392→    log::info!(
3393→        "building custom Go frontend with {} native generator(s)...",
3394→        native_gens.len()
3395→    );
3396→
3397→    // Locate the shatter-go source directory. In development it's a sibling of
3398→    // shatter-cli; for installed binaries it would be embedded (future work).
3399→    let shatter_go_dir = locate_shatter_go_source()
3400→        .ok_or_else(|| "cannot find shatter-go source directory; \
3401→            ensure you are running from the shatter repo or set SHATTER_GO_SRC".to_string())?;
3402→
3403→    // Create temp build directory
3404→    let temp_dir = tempfile::tempdir()
3405→        .map_err(|e| format!("failed to create temp dir: {e}"))?;
3406→    let build_dir = temp_dir.path();
3407→
3408→    // Initialize Go module
3409→    run_go_cmd(build_dir, &["mod", "init", "shatter-custom-frontend"])?;
3410→
3411→    // Copy user generator files into a usergens/ package in the build dir.
3412→    let usergens_dir = build_dir.join("usergens");
3413→    std::fs::create_dir_all(&usergens_dir)
3414→        .map_err(|e| format!("failed to create usergens dir: {e}"))?;
3415→
3416→    // Resolve generator file paths and copy them
3417→    let project_root = shatter_dir.parent().unwrap_or(Path::new("."));
3418→    for (_name, rel_path) in &native_gens {
3419→        let src = if rel_path.is_absolute() {
3420→            rel_path.clone()
3421→        } else {
3422→            project_root.join(rel_path)
3423→        };
3424→        let filename = src.file_name()
3425→            .ok_or_else(|| format!("generator path has no filename: {}", src.display()))?;
3426→        std::fs::copy(&src, usergens_dir.join(filename))
3427→            .map_err(|e| format!("failed to copy {}: {e}", src.display()))?;
3428→    }
3429→
3430→    // Ensure the usergens directory has a valid package declaration.
3431→    // Write a package file that re-exports the generator functions.
3432→    let usergens_pkg = "package usergens\n";
3433→    // Check if any copied file already declares `package usergens`; if not,
3434→    // they might declare a different package. We'll write a minimal file.
3435→    let has_package_decl = native_gens.iter().any(|(_, rel_path)| {
3436→        let src = if rel_path.is_absolute() { rel_path.clone() } else { project_root.join(rel_path) };
3437→        std::fs::read_to_string(&src)
3438→            .map(|s| s.contains("package usergens"))

