 1→//! Per-function fingerprinting for staleness detection.
 2→//!
 3→//! A fingerprint is a stable SHA-256 hash of a function's source text,
 4→//! parameter types, and branch structure. When a fingerprint matches a
 5→//! previously cached value, the function is unchanged and can be skipped
 6→//! during re-exploration.
 7→
 8→use std::collections::{HashMap, HashSet};
 9→use std::fmt::Write as _;
10→use std::path::Path;
11→
12→use sha2::{Digest, Sha256};
13→
14→use crate::protocol::FunctionAnalysis;
15→
16→/// Compute a hex-encoded SHA-256 fingerprint for a function.
17→///
18→/// The fingerprint incorporates:
19→/// - The function's source text (verbatim, including whitespace)
20→/// - Parameter names and types (sorted by name for stability)
21→/// - Branch structure: IDs, lines, condition text, types (sorted by ID)
22→///
23→/// Any change to these inputs produces a different fingerprint.
24→pub fn compute_function_fingerprint(source_text: &str, analysis: &FunctionAnalysis) -> String {
25→    let mut hasher = Sha256::new();
26→
27→    // Hash source text.
28→    hasher.update(b"source:");
29→    hasher.update(source_text.as_bytes());
30→
31→    // Hash parameters (sorted by name for determinism).
32→    let mut params: Vec<_> = analysis
33→        .params
34→        .iter()
35→        .map(|p| {
36→            let mut s = String::new();
37→            let _ = write!(s, "{}:{:?}", p.name, p.typ);
38→            if let Some(ref tn) = p.type_name {
39→                let _ = write!(s, "/{tn}");
40→            }
41→            s
42→        })
43→        .collect();
44→    params.sort();
45→
46→    hasher.update(b"params:");
47→    for p in &params {
48→        hasher.update(p.as_bytes());
49→        hasher.update(b"\n");
50→    }
51→
52→    // Hash branch structure (sorted by branch ID for determinism).
53→    let mut branches: Vec<_> = analysis
54→        .branches
55→        .iter()
56→        .map(|b| {
57→            let mut s = String::new();
58→            let _ = write!(s, "{}:{}:{:?}:{}", b.id, b.line, b.branch_type, b.condition_text);
59→            s
60→        })

  1→//! SCM (source control) provider for querying changed files.
  2→//!
  3→//! Shells out to `git` with zero external dependencies. Used by `--changed`
  4→//! and `--since` CLI flags to restrict scan scope to modified files.
  5→
  6→use std::path::{Path, PathBuf};
  7→use std::process::Command;
  8→
  9→/// Errors from SCM operations.
 10→#[derive(Debug, thiserror::Error)]
 11→pub enum ScmError {
 12→    #[error("not a git repository (or any parent): {path}")]
 13→    NotARepo { path: PathBuf },
 14→
 15→    #[error("git executable not found")]
 16→    GitNotFound,
 17→
 18→    #[error("git command failed (exit {code}): {stderr}")]
 19→    GitFailed { code: i32, stderr: String },
 20→
 21→    #[error("I/O error running git: {0}")]
 22→    Io(#[from] std::io::Error),
 23→}
 24→
 25→/// Trait for querying changed files from source control.
 26→pub trait ScmProvider {
 27→    /// Files with uncommitted changes (staged + unstaged vs HEAD).
 28→    /// If `include_untracked` is true, also includes untracked files
 29→    /// (excluding gitignored ones).
 30→    fn changed_files(&self, root: &Path, include_untracked: bool) -> Result<Vec<PathBuf>, ScmError>;
 31→
 32→    /// Files changed between `base_ref` and HEAD (merge-base diff).
 33→    fn diff_files(&self, root: &Path, base_ref: &str) -> Result<Vec<PathBuf>, ScmError>;
 34→}
 35→
 36→/// Git-based SCM provider. Shells out to `git` via `std::process::Command`.
 37→#[derive(Debug)]
 38→pub struct GitProvider;
 39→
 40→impl ScmProvider for GitProvider {
 41→    fn changed_files(&self, root: &Path, include_untracked: bool) -> Result<Vec<PathBuf>, ScmError> {
 42→        // Staged + unstaged changes vs HEAD
 43→        let output = run_git(root, &["diff", "--name-only", "HEAD"])?;
 44→        let mut files = parse_file_list(&output, root);
 45→
 46→        // Also include staged-only changes (new files that are staged but not yet committed)
 47→        let staged_output = run_git(root, &["diff", "--name-only", "--cached"])?;
 48→        let staged_files = parse_file_list(&staged_output, root);
 49→        for f in staged_files {
 50→            if !files.contains(&f) {
 51→                files.push(f);
 52→            }
 53→        }
 54→
 55→        if include_untracked {
 56→            let untracked_output =
 57→                run_git(root, &["ls-files", "--others", "--exclude-standard"])?;
 58→            let untracked = parse_file_list(&untracked_output, root);
 59→            for f in untracked {
 60→                if !files.contains(&f) {
 61→                    files.push(f);
 62→                }
 63→            }
 64→        }
 65→
 66→        files.sort();
 67→        files.dedup();
 68→        Ok(files)
 69→    }
 70→
 71→    fn diff_files(&self, root: &Path, base_ref: &str) -> Result<Vec<PathBuf>, ScmError> {
 72→        // Three-dot diff: changes between merge-base(base_ref, HEAD) and HEAD
 73→        let range = format!("{base_ref}...HEAD");
 74→        let output = run_git(root, &["diff", "--name-only", &range])?;
 75→        let mut files = parse_file_list(&output, root);
 76→        files.sort();
 77→        files.dedup();
 78→        Ok(files)
 79→    }
 80→}
 81→
 82→/// Detect the SCM provider for the given directory.
 83→/// Currently only supports Git.
 84→pub fn detect_provider(root: &Path) -> Result<GitProvider, ScmError> {
 85→    let status = Command::new("git")
 86→        .args(["rev-parse", "--git-dir"])
 87→        .current_dir(root)
 88→        .stdout(std::process::Stdio::null())
 89→        .stderr(std::process::Stdio::null())
 90→        .status();
 91→
 92→    match status {
 93→        Ok(s) if s.success() => Ok(GitProvider),
 94→        Ok(_) => Err(ScmError::NotARepo {
 95→            path: root.to_path_buf(),
 96→        }),
 97→        Err(e) if e.kind() == std::io::ErrorKind::NotFound => Err(ScmError::GitNotFound),
 98→        Err(e) => Err(ScmError::Io(e)),
 99→    }
100→}
101→
102→/// Run a git command in the given directory and return stdout as a string.
103→fn run_git(root: &Path, args: &[&str]) -> Result<String, ScmError> {
104→    let output = Command::new("git")
105→        .args(args)
106→        .current_dir(root)
107→        .output()
108→        .map_err(|e| {
109→            if e.kind() == std::io::ErrorKind::NotFound {
110→                ScmError::GitNotFound
111→            } else {
112→                ScmError::Io(e)
113→            }
114→        })?;
115→
116→    if !output.status.success() {
117→        let stderr = String::from_utf8_lossy(&output.stderr).trim().to_string();
118→        let code = output.status.code().unwrap_or(-1);
119→        return Err(ScmError::GitFailed { code, stderr });
120→    }
121→
122→    Ok(String::from_utf8_lossy(&output.stdout).to_string())
123→}
124→
125→/// Parse newline-separated file paths from git output into absolute paths.
126→fn parse_file_list(output: &str, root: &Path) -> Vec<PathBuf> {
127→    output
128→        .lines()
129→        .filter(|line| !line.is_empty())
130→        .map(|line| root.join(line.trim()))
131→        .collect()
132→}
