            emit_tests,
            dry_run,
            resume,
            progress,
            core_sample,
            seed,
            batch,
            max_iterations,
            cache_dir,
            no_cache,
            request_timeout,
            exec_timeout,
            build_timeout,
            stratum,
            genetic: _,
            genetic_population: _,
            genetic_generations: _,
            genetic_timeout: _,
