/// Shatter: automatic exploratory testing via concolic execution.
#[derive(Parser, Debug)]
#[command(name = "shatter", version, about)]
struct Cli {
    /// Log verbosity level: error, warn, info (default), debug, trace.
    #[arg(long, global = true, default_value = "info")]
    log_level: LogLevel,

    /// Increase verbosity (-v = debug, -vv = trace).
    #[arg(short = 'v', long = "verbose", global = true, action = clap::ArgAction::Count)]
    verbose: u8,

    /// Decrease verbosity to warnings and errors only.
    #[arg(short = 'q', long = "quiet", global = true)]
    quiet: bool,

    /// Show per-function performance stats.
    #[arg(long, global = true)]
    perf: bool,

    /// Override auto-detected project root directory.
    #[arg(long, global = true, value_name = "DIR")]
    project_dir: Option<std::path::PathBuf>,

    /// When to use terminal colors: always, auto (default), or never.
    /// Respects the NO_COLOR environment variable (auto treats it as never).
    #[arg(long, global = true, default_value = "auto", value_name = "WHEN")]
    color: ColorMode,

    #[command(subcommand)]
    command: CliCommand,
}

#[derive(Clone, Copy, Debug, ValueEnum)]
enum ColorMode {
    Always,
    Auto,
    Never,
}

impl ColorMode {
    fn use_color(self) -> bool {
        match self {
            ColorMode::Always => true,
            ColorMode::Never => false,
            ColorMode::Auto => {
                std::io::stdout().is_terminal() && std::env::var_os("NO_COLOR").is_none()
            }
        }
    }
}

impl Cli {
    /// Resolve the effective log level from --log-level, -v, and -q flags.
    fn effective_log_level(&self) -> LogLevel {
        if self.quiet {
            return LogLevel::Warn;
        }
        match self.verbose {
            0 => self.log_level,
            1 => LogLevel::Debug,
            _ => LogLevel::Trace,
        }
    }

}

/// Resolve the project root: explicit `project_dir` wins, otherwise auto-detect from `reference_path`.
fn resolve_project_root(project_dir: Option<&Path>, reference_path: &Path) -> Option<String> {
    if let Some(dir) = project_dir {
        Some(dir.to_string_lossy().into_owned())
    } else {
        shatter_core::project::detect_project_root(reference_path)
            .map(|r| r.path.to_string_lossy().into_owned())
    }
}

/// Strip `root` prefix from `path` to produce a relative path string.
/// Falls back to the full path if stripping fails.
fn relativize_path(path: &Path, root: &Path) -> String {
    path.strip_prefix(root)
        .unwrap_or(path)
        .to_string_lossy()
        .into_owned()
}

/// Terminal color support.
struct Colors {
    bold: &'static str,
    dim: &'static str,
    reset: &'static str,
}

impl Colors {
    fn new(use_color: bool) -> Self {
        if use_color {
            Colors {
                bold: "\x1b[1m",
                dim: "\x1b[2m",
                reset: "\x1b[0m",
            }
        } else {
            Colors {
                bold: "",
                dim: "",
                reset: "",
            }
        }
    }
}

/// Print Markdown to stdout, rendered with termimad formatting when `use_color` is true.
fn print_markdown(md: &str, use_color: bool) {
    if use_color {
        termimad::print_text(md);
    } else {
        print!("{md}");
    }
}

